firebase.auth().onAuthStateChanged((e=>{if(e=firebase.auth().currentUser){var t=document.getElementById("login-signup"),n=document.getElementById("loggedin-tools"),s=document.getElementById("userDisplayName"),d=document.getElementById("userProfileImage"),o=document.getElementById("adminLink");t.classList.add("d-none"),n.classList.remove("d-none"),s.innerText=e.displayName,d.src=e.photoURL,firebase.firestore().collection("users").doc(e.uid).get().then((e=>{e.exists&&"admin"==e.data().role&&o.classList.remove("d-none")}))}}));